let items=$input.all();
let pos={net:[],day:[]},hold=[],marg={},pnl=0;
for(let it of items){
 let d=it.json||{};
 let data=d.data||d;
 if(data.net||data.day){
  let mapPos=(arr)=>arr.map(p=>({sym:p.tradingsymbol,qty:p.quantity,avg:p.average_price,ltp:p.last_price,pnl:p.pnl||0,ur:p.unrealised||0,rel:p.realised||0}));
  pos={net:mapPos(data.net||[]),day:mapPos(data.day||[])};
  for(let p of pos.net)pnl+=p.pnl||0;
  for(let p of pos.day)pnl+=p.pnl||0;
 }else if(Array.isArray(data)){
  hold=data.map(h=>({sym:h.tradingsymbol,qty:h.quantity,avg:h.average_price,ltp:h.last_price,pnl:h.pnl||0,ur:h.unrealised||0}));
  for(let h of hold)pnl+=h.pnl||0;
 }else if(data.equity||data.commodity){
  let e=data.equity||{};
  marg={cash:e.available?e.available.cash:0,net:e.net||0,used:e.utilised?e.utilised.exposure||0:0};
 }
}
let posList=pos.net.concat(pos.day);
let hasPnl=pnl!==0;
let posSummary=posList.map(p=>p.sym+' Qty:'+p.qty+' LTP:'+p.ltp+' PnL:'+p.pnl).join('. ');
let holdSummary=hold.map(h=>h.sym+' Qty:'+h.qty).join(', ');
let prompt='Analyze portfolio snapshot. Positions: '+(posSummary||'none')+'. Holdings: '+(holdSummary||'none')+'. Total PnL: '+pnl+'. Margin cash: '+(marg.cash||0)+' used: '+(marg.used||0)+'. Flag ONLY problems needing attention. If all ok, say ALL_OK.';
return [{json:{_pos:posList,_hold:hold,_marg:marg,_pnl:pnl,_prompt:prompt,_has_items:posList.length>0||hold.length>0||hasPnl}}]

let items=$input.all(),r=[];
for(let it of items){
 let d=it.json,url='http://ollama:11434/api/generate',body=JSON.stringify({model:'llama3:8b',prompt:d._prompt,stream:false});
 try{
  let resp=await this.helpers.httpRequest({method:'POST',url,body,headers:{'Content-Type':'application/json'},timeout:120000});
  let reply=String(resp.response||'').trim();
  if(reply.includes('ALL_OK')&&d._pnl===0&&d._pos.length===0){continue}
  let msg='📊 Portfolio Alert: '+reply;
  r.push({json:{_tg:msg,_wa:msg,_reply:reply}})
 }catch(e){}
}
return r
